from __future__ import annotations

import argparse
import os
import shutil
import subprocess
import sys
import textwrap
from pathlib import Path


DOCS = """
Dependency Management Best Practices
====================================

Goal
----
Keep dependency versions consistent across development, CI, staging, and production.

Recommended approaches
----------------------
1. requirements.txt with hashes
   - Maintain a human-edited input file, typically requirements.in or requirements.txt.in.
   - Generate a fully pinned output file with exact versions and hashes.
   - Install from the locked file in all environments.

2. Poetry lock files
   - Maintain dependencies in pyproject.toml.
   - Commit poetry.lock to source control.
   - Use poetry install for reproducible environments.

General rules
-------------
- Commit lock files to version control.
- Do not hand-edit generated lock files unless you know exactly what you are doing.
- Separate direct dependencies from transitive dependencies.
- Re-lock whenever dependency constraints change.
- Use the same lock artifact in development and production.
- Prefer exact pinning for production deployments.
- Review dependency updates for security and compatibility.

Option A: requirements.txt + hashes
-----------------------------------
Recommended files:
- requirements.in        : top-level direct dependencies
- requirements.txt       : generated lock file with pinned versions and hashes
- requirements-dev.in    : dev/test tools
- requirements-dev.txt   : generated dev lock file

Typical workflow:
1. Add/update direct dependencies in requirements.in.
2. Generate the lock file:
     pip install pip-tools
     pip-compile --generate-hashes --output-file requirements.txt requirements.in
3. Install using the lock file:
     pip install --require-hashes -r requirements.txt
4. For development extras, use a separate dev input file and lock file.

Updating dependencies:
- Update a single package:
     pip-compile --upgrade-package PACKAGE --generate-hashes --output-file requirements.txt requirements.in
- Update all packages:
     pip-compile --upgrade --generate-hashes --output-file requirements.txt requirements.in

Production recommendation:
- Install only from the locked file.
- Use --require-hashes to ensure integrity and prevent drift.

Option B: Poetry
-----------------
Recommended files:
- pyproject.toml : dependency declarations
- poetry.lock    : resolved lock file

Typical workflow:
1. Add/update dependencies:
     poetry add PACKAGE
     poetry add --group dev PACKAGE
2. Resolve and lock:
     poetry lock
3. Install:
     poetry install

Updating dependencies:
- Update all:
     poetry update
- Update a single package:
     poetry update PACKAGE

Exporting to requirements.txt:
- If you need a pip-based deployment:
     poetry export -f requirements.txt --output requirements.txt --with-hashes
- Then install with:
     pip install --require-hashes -r requirements.txt

CI/CD guidance
--------------
- Validate that lock files are up to date.
- Fail builds if the lock file changes unexpectedly.
- Rebuild environments from scratch in CI to catch missing pins.
- Use a clean virtual environment for every test run.

Common mistakes
---------------
- Editing generated lock files by hand.
- Mixing unpinned and pinned dependencies in production.
- Forgetting to commit lock file updates.
- Installing from a broad spec like 'package>=1.0' in production.
- Allowing development and production to use different dependency sources.

Suggested team policy
---------------------
- Direct dependencies are declared in:
    requirements.in or pyproject.toml
- Locked artifacts are committed:
    requirements.txt and/or poetry.lock
- Production deployments install only from locked artifacts.
- Dependency updates are made in dedicated pull requests.
- Security updates are reviewed and applied promptly.
""".strip()


def run(cmd: list[str], cwd: str | None = None) -> int:
    print("+ " + " ".join(cmd))
    proc = subprocess.run(cmd, cwd=cwd)
    return proc.returncode


def which_or_fail(executable: str) -> str:
    path = shutil.which(executable)
    if not path:
        raise SystemExit(f"Required executable not found in PATH: {executable}")
    return path


def cmd_docs(_: argparse.Namespace) -> int:
    print(DOCS)
    return 0


def cmd_pip_compile(args: argparse.Namespace) -> int:
    which_or_fail("pip-compile")
    input_file = Path(args.input)
    output_file = Path(args.output)
    if not input_file.exists():
        raise SystemExit(f"Input file not found: {input_file}")

    cmd = [
        "pip-compile",
        "--generate-hashes",
        "--output-file",
        str(output_file),
        str(input_file),
    ]
    if args.upgrade:
        cmd.append("--upgrade")
    for pkg in args.upgrade_package or []:
        cmd.extend(["--upgrade-package", pkg])

    return run(cmd, cwd=args.cwd)


def cmd_poetry_lock(args: argparse.Namespace) -> int:
    which_or_fail("poetry")
    project_dir = Path(args.project_dir)
    pyproject = project_dir / "pyproject.toml"
    if not pyproject.exists():
        raise SystemExit(f"pyproject.toml not found in: {project_dir}")

    cmd = ["poetry", "lock"]
    if args.no_update:
        cmd.append("--no-update")
    return run(cmd, cwd=str(project_dir))


def cmd_poetry_export(args: argparse.Namespace) -> int:
    which_or_fail("poetry")
    project_dir = Path(args.project_dir)
    pyproject = project_dir / "pyproject.toml"
    lock_file = project_dir / "poetry.lock"
    if not pyproject.exists():
        raise SystemExit(f"pyproject.toml not found in: {project_dir}")
    if not lock_file.exists():
        raise SystemExit(f"poetry.lock not found in: {project_dir}")

    cmd = [
        "poetry",
        "export",
        "-f",
        "requirements.txt",
        "--output",
        str(Path(args.output)),
    ]
    if args.with_hashes:
        cmd.append("--with-hashes")
    if args.with_dev:
        cmd.append("--with")
        cmd.append("dev")
    if args.without_dev:
        cmd.append("--without")
        cmd.append("dev")
    return run(cmd, cwd=str(project_dir))


def cmd_update_check(args: argparse.Namespace) -> int:
    if args.tool == "pip":
        req = Path(args.file)
        if not req.exists():
            raise SystemExit(f"File not found: {req}")
        print("Recommended check:")
        print(f"  pip-compile --dry-run --generate-hashes --output-file {req} {req}")
        print("If the generated output differs, commit the updated lock file.")
        return 0

    if args.tool == "poetry":
        project_dir = Path(args.project_dir)
        lock_file = project_dir / "poetry.lock"
        if not lock_file.exists():
            raise SystemExit(f"poetry.lock not found in: {project_dir}")
        print("Recommended check:")
        print(f"  cd {project_dir}")
        print("  poetry check")
        print("  poetry lock --no-update")
        print("If poetry.lock changes, commit the updated lock file.")
        return 0

    raise SystemExit(f"Unknown tool: {args.tool}")


def build_parser() -> argparse.ArgumentParser:
    parser = argparse.ArgumentParser(
        prog="dep_lock_manager.py",
        description="Manage Python dependency lock files and print best-practice documentation.",
    )
    sub = parser.add_subparsers(dest="command", required=True)

    p_docs = sub.add_parser("docs", help="Print dependency management best-practice documentation.")
    p_docs.set_defaults(func=cmd_docs)

    p_pip = sub.add_parser("pip-compile", help="Generate a pinned requirements.txt with hashes using pip-compile.")
    p_pip.add_argument("--input", default="requirements.in", help="Input spec file, usually requirements.in.")
    p_pip.add_argument("--output", default="requirements.txt", help="Output lock file.")
    p_pip.add_argument("--cwd", default=None, help="Working directory for the command.")
    p_pip.add_argument("--upgrade", action="store_true", help="Upgrade all packages.")
    p_pip.add_argument(
        "--upgrade-package",
        action="append",
        default=[],
        help="Upgrade a specific package. Can be passed multiple times.",
    )
    p_pip.set_defaults(func=cmd_pip_compile)

    p_poetry_lock = sub.add_parser("poetry-lock", help="Generate/update poetry.lock.")
    p_poetry_lock.add_argument("--project-dir", default=".", help="Project directory containing pyproject.toml.")
    p_poetry_lock.add_argument("--no-update", action="store_true", help="Do not update already resolved versions.")
    p_poetry_lock.set_defaults(func=cmd_poetry_lock)

    p_poetry_export = sub.add_parser("poetry-export", help="Export Poetry lock to requirements.txt.")
    p_poetry_export.add_argument("--project-dir", default=".", help="Project directory containing pyproject.toml and poetry.lock.")
    p_poetry_export.add_argument("--output", default="requirements.txt", help="Output requirements file.")
    p_poetry_export.add_argument("--with-hashes", action="store_true", default=True, help="Include hashes in export.")
    p_poetry_export.add_argument("--without-hashes", dest="with_hashes", action="store_false", help="Exclude hashes in export.")
    p_poetry_export.add_argument("--with-dev", action="store_true", help="Include dev dependencies.")
    p_poetry_export.add_argument("--without-dev", action="store_true", help="Exclude dev dependencies.")
    p_poetry_export.set_defaults(func=cmd_poetry_export)

    p_check = sub.add_parser("update-check", help="Print recommended commands to verify lock files are up to date.")
    p_check.add_argument("tool", choices=["pip", "poetry"], help="Tool to check.")
    p_check.add_argument("--file", default="requirements.txt", help="Requirements file for pip workflow.")
    p_check.add_argument("--project-dir", default=".", help="Project directory for Poetry workflow.")
    p_check.set_defaults(func=cmd_update_check)

    return parser


def main() -> int:
    parser = build_parser()
    args = parser.parse_args()
    return args.func(args)


if __name__ == "__main__":
    raise SystemExit(main())